                MG_Utils.addClass(rightSidebar, 'trailerVideoAd');
            }

            if (typeof thumbsLayoutUpdate !== 'undefined' && thumbsLayoutUpdate) {
                document.dispatchEvent(new Event('togglePlayerSize'));
            }
        };

